INSERT INTO public.autoevaluacion VALUES (209, 'Acuerdo 02 2020', 'DERECHO', 'F1. Proyecto Educativo del Programa e Identidad Institucional', 'C1. Proyecto Educativo del Programa', 'A1. Demostrar coherencia del Proyecto Educativo del Programa (PEP) o el que haga sus veces, con los lineamientos y políticas Institucionales, así como en la definición de objetivos de formación y resultados de aprendizaje y la manera cómo el PEP ha ido mejorando, como resultado de los procesos de aseguramiento de la calidad, la consolidación de la identidad Institucional y la relación que mantiene con la comunidad y sus grupos de interés.', 'I1. Existencia de ejercicios de análisis y actualización del PEP en coherencia con la identidad, los lineamientos y políticas Institucionales, la definición de los objetivos de formación, los resultados de aprendizaje y cómo ha permitido mejorar la relación con la comunidad y los grupos de interés.', 'GF', NULL, 'P', 3.50, 'https://drive.google.com/drive/folders/1OBtkwOamD_Xer40E-NqXnOSiWnLnfsc4', NULL, '{"SCRIT": "", "FACTOR": "F1. Proyecto Educativo del Programa e Identidad Institucional", "PROGRAMA": "DERECHO", "INDICADOR": "I1. Existencia de ejercicios de análisis y actualización del PEP en coherencia con la identidad, los lineamientos y políticas Institucionales, la definición de los objetivos de formación, los resultados de aprendizaje y cómo ha permitido mejorar la relación con la comunidad y los grupos de interés.", "Componente": "P", "Evidencias": "https://drive.google.com/drive/folders/1OBtkwOamD_Xer40E-NqXnOSiWnLnfsc4", "Acuerdo MEN": "Acuerdo 02 2020", "Instrumento": "GF", "CARACTERÍSTICA": "C1. Proyecto Educativo del Programa", "ASPECTOS POR EVALUAR": "A1. Demostrar coherencia del Proyecto Educativo del Programa (PEP) o el que haga sus veces, con los lineamientos y políticas Institucionales, así como en la definición de objetivos de formación y resultados de aprendizaje y la manera cómo el PEP ha ido mejorando, como resultado de los procesos de aseguramiento de la calidad, la consolidación de la identidad Institucional y la relación que mantiene con la comunidad y sus grupos de interés.", "Calificación Indicador": "3.5", "Información para tener en cuenta": ""}', 10, 10, '2026-04-30 11:25:42.468-05', '2026-04-30 11:25:42.468-05');
