INSERT INTO public.autoevaluacion VALUES (244, 'Acuerdo 02 2055', 'DERECHO', 'F3. Profesores', 'C15. Evaluación de profesores', 'A36. Apreciación de los profesores, directivos y estudiantes sobre los criterios y mecanismos para la evaluación de los profesores; su transparencia, equidad y eficacia y; su coherencia con la naturaleza de la institución, el nivel de formación y la modalidad del programa, junto con las acciones emprendidas como resultado de dichas apreciaciones.', 'I29. Análisis de la apreciación de los profesores, directivos y estudiantes sobre los criterios y mecanismos para la evaluación de los profesores; su transparencia, equidad y eficacia y; su coherencia con la naturaleza de la institución, el nivel de formación y la modalidad del programa, que incluya las acciones emprendidas como resultado de dichas apreciaciones.', 'ENC', NULL, 'P/I', 3.70, 'https://drive.google.com/drive/folders/1TCmnMoG6pjR1SyZG4i1H2VKA0tYrWLCn', NULL, '{"SCRIT": "", "FACTOR": "F3. Profesores", "PROGRAMA": "DERECHO", "INDICADOR": "I29. Análisis de la apreciación de los profesores, directivos y estudiantes sobre los criterios y mecanismos para la evaluación de los profesores; su transparencia, equidad y eficacia y; su coherencia con la naturaleza de la institución, el nivel de formación y la modalidad del programa, que incluya las acciones emprendidas como resultado de dichas apreciaciones.", "Componente": "P/I", "Evidencias": "https://drive.google.com/drive/folders/1TCmnMoG6pjR1SyZG4i1H2VKA0tYrWLCn", "Acuerdo MEN": "Acuerdo 02 2055", "Instrumento": "ENC", "CARACTERÍSTICA": "C15. Evaluación de profesores", "ASPECTOS POR EVALUAR": "A36. Apreciación de los profesores, directivos y estudiantes sobre los criterios y mecanismos para la evaluación de los profesores; su transparencia, equidad y eficacia y; su coherencia con la naturaleza de la institución, el nivel de formación y la modalidad del programa, junto con las acciones emprendidas como resultado de dichas apreciaciones.", "