INSERT INTO public.autoevaluacion VALUES (250, 'Acuerdo 02 2061', 'DERECHO', 'F5. Aspectos académicos y resultados de aprendizaje', 'C18. Integralidad de los aspectos curriculares', 'A42. Resultados de la aplicación de ejercicios continuos de evaluación de la integralidad del currículo que conduzcan a la realización de ajustes y mejoras que impactan a la formación en valores, actitudes, aptitudes, conocimientos, métodos, capacidades y habilidades, de acuerdo con el estado del arte y con el ejercicio de la disciplina, profesión, ocupación u oficio, y que busca la formación integral del estudiante en coherencia con la misión Institucional y los objetivos propios del programa académico.', 'I35. Existencia de ejercicios continuos de evaluación de la integralidad del currículo que hayan permitido ajustes y mejoras en la formación en valores, actitudes, aptitudes, conocimientos, métodos, capacidades y habilidades, de acuerdo con el ejercicio de la disciplina o profesión, en coherencia con la misión institucional y objetivos del programa académico.', 'GF', NULL, 'P', 3.90, 'https://drive.google.com/drive/folders/1OBtkwOamD_Xer40E-NqXnOSiWnLnfsc4', NULL, '{"SCRIT": "", "FACTOR": "F5. Aspectos académicos y resultados de aprendizaje", "PROGRAMA": "DERECHO", "INDICADOR": "I35. Existencia de ejercicios continuos de evaluación de la integralidad del currículo que hayan permitido ajustes y mejoras en la formación en valores, actitudes, aptitudes, conocimientos, métodos, capacidades y habilidades, de acuerdo con el ejercicio de la disciplina o profesión, en coherencia con la misión institucional y objetivos del programa académico.", "Componente": "P", "Evidencias": "https://drive.google.com/drive/folders/1OBtkwOamD_Xer40E-NqXnOSiWnLnfsc4", "Acuerdo MEN": "Acuerdo 02 2061", "Instrumento": "GF", "CARACTERÍSTICA": "C18. Integralidad de los aspectos curriculares", "ASPECTOS POR EVALUAR": "A42. Resultados de la aplicación de ejercicios continuos de evaluación de la integralidad del currículo que conduzcan a la realización de ajustes y mejoras que impactan a la formación en valores, actitudes, aptitudes, conocimientos, métodos, capacidades y habilidades, de acuerdo con el estado del arte y con el ejercicio de la disciplina, profesión, ocupación u oficio, y que busca la formación integral del estudiante en coherencia con la misión Institucional y los objetivos propios del programa académico.", "Calificación Indicador": "3.9", "Información para tener en cuenta": ""}', 10, 10, '2026-04-30 11:25:42.561-05', '2026-04-30 11:25:42.561-05');
