INSERT INTO public.autoevaluacion VALUES (276, 'Acuerdo 02 2087', 'DERECHO', 'F7. Interacción con el entorno nacional e internacional', 'C31. Inserción del programa en contextos académicos nacionales e internacionales', 'A68. Evidencia del efecto de la aplicación de políticas y estrategias de cooperación con comunidades, nacionales e internacionales, en el desarrollo de labores formativas, académicas, docentes, científicas, culturales, deportivas y de extensión, así como en aspectos curriculares y en la revisión de tendencias y referentes nacionales e internacionales que contribuyan al mejoramiento continuo del programa.', 'I61. Análisis del efecto de la aplicación de políticas y estrategias de cooperación con comunidades, nacionales e internacionales, en el desarrollo de labores formativas, académicas, docentes, científicas, culturales, deportivas y de extensión, así como en aspectos curriculares y en la revisión de tendencias y referentes nacionales e internacionales que contribuyan al mejoramiento continuo del programa.', 'TA', NULL, 'P', 4.30, 'https://drive.google.com/drive/folders/1uiwmVlDUhEm8xWCGFw0d9W2GK2FmVVzO', 'Información relacionada con la movilidad de estudiantes y docentes, entrante, saliente, virtual del programa correspondiente.
